// Re-instantiate the trigger-protected page-mapping foralls from the ensures
// of BOTH runs. The two ensures-foralls share #![trigger ...] forms over
// post1_self_.page_is_mapped / post1_self_.page_mappings and the parallel
// post2_self_ forms, so z3 never lines them up on the same ground term.
// Restating each forall here forces both sets of ground triggers into the
// e-graph at the same path point.
assert(forall|p: PagePtr|
    #![trigger post1_self_.page_is_mapped(p)]
    #![trigger post1_self_.page_mappings(p)]
    post1_self_.page_is_mapped(p) && p != r1
        ==> post1_self_.page_io_mappings(p) =~= pre_self_.page_io_mappings(p));
assert(forall|p: PagePtr|
    #![trigger post1_self_.page_is_mapped(p)]
    #![trigger post1_self_.page_mappings(p)]
    post1_self_.page_is_mapped(p)
        ==> post1_self_.page_mappings(p) =~= pre_self_.page_mappings(p));
assert(forall|p: PagePtr|
    #![trigger post2_self_.page_is_mapped(p)]
    #![trigger post2_self_.page_mappings(p)]
    post2_self_.page_is_mapped(p) && p != r2
        ==> post2_self_.page_io_mappings(p) =~= pre_self_.page_io_mappings(p));
assert(forall|p: PagePtr|
    #![trigger post2_self_.page_is_mapped(p)]
    #![trigger post2_self_.page_mappings(p)]
    post2_self_.page_is_mapped(p)
        ==> post2_self_.page_mappings(p) =~= pre_self_.page_mappings(p));

// Re-state the monotonicity forall (pre_self_.page_is_mapped(p) ==> postN.page_is_mapped(p))
// for both runs so z3 has both ground triggers available.
assert(forall|p: PagePtr| #![auto]
    post1_self_.page_is_mapped(p) <== pre_self_.page_is_mapped(p));
assert(forall|p: PagePtr| #![auto]
    post2_self_.page_is_mapped(p) <== pre_self_.page_is_mapped(p));

// Re-state the container-ownership forall for both runs.
assert(forall|c: ContainerPtr| #![auto]
    post1_self_.container_map_4k@.dom().contains(c) && c_ptr != c
        ==> post1_self_.get_container_owned_pages(c)
              =~= pre_self_.get_container_owned_pages(c));
assert(forall|c: ContainerPtr| #![auto]
    post2_self_.container_map_4k@.dom().contains(c) && c_ptr != c
        ==> post2_self_.get_container_owned_pages(c)
              =~= pre_self_.get_container_owned_pages(c));

// Bridge the stable, per-size set spec-fns through pre_self_ so both runs
// agree on the unchanged buckets.  Each conjunct is a direct =~= chain
// through the corresponding ensures clause on each run.
assert(post1_self_.free_pages_2m() =~= post2_self_.free_pages_2m());
assert(post1_self_.free_pages_1g() =~= post2_self_.free_pages_1g());
assert(post1_self_.allocated_pages_4k() =~= post2_self_.allocated_pages_4k());
assert(post1_self_.allocated_pages_2m() =~= post2_self_.allocated_pages_2m());
assert(post1_self_.allocated_pages_1g() =~= post2_self_.allocated_pages_1g());
assert(post1_self_.mapped_pages_2m() =~= post2_self_.mapped_pages_2m());
assert(post1_self_.mapped_pages_1g() =~= post2_self_.mapped_pages_1g());

// Container-map domains agree across both runs (transitively via pre_self_).
assert(post1_self_.container_map_4k@.dom() =~= post2_self_.container_map_4k@.dom());
assert(post1_self_.container_map_2m@.dom() =~= post2_self_.container_map_2m@.dom());
assert(post1_self_.container_map_1g@.dom() =~= post2_self_.container_map_1g@.dom());

// The per-container owned-page sets for c_ptr both equal the same insertion
// into pre_self_.get_container_owned_pages(c_ptr), specialised at r1 and r2.
assert(post1_self_.get_container_owned_pages(c_ptr)
        =~= pre_self_.get_container_owned_pages(c_ptr).insert(r1));
assert(post2_self_.get_container_owned_pages(c_ptr)
        =~= pre_self_.get_container_owned_pages(c_ptr).insert(r2));
